-- Seed the 成长记录 (Growth Record) system tool and its 41 measurement records.
-- Records were transcribed from a parent's growth-tracking screenshot (child born ~2020-03-12).
-- age_months is computed from the measurement date relative to the birth date.
-- All INSERTs use ON CONFLICT DO NOTHING to be idempotent.

-- Tool
VALUES (
    '00000000-0000-0000-0000-000000000203',
    '00000000-0000-0000-0000-000000000001',
    '成长记录',
    'Track a child''s height and weight over time with WHO growth percentile reference bands',
    'system',
    'active',
    '{"type":"object","properties":{"date":{"type":"string","format":"date"},"height_cm":{"type":"number"},"weight_kg":{"type":"number"},"head_circ_cm":{"type":"number"},"age_months":{"type":"number"},"age_label":{"type":"string"},"note":{"type":"string"}}}'
)
ON CONFLICT DO NOTHING;

-- Tool version v1
VALUES (
    '00000000-0000-0000-0000-000000000303',
    '00000000-0000-0000-0000-000000000203',
    1,
    'Initial version',
    '{"type":"object","properties":{"date":{"type":"string","format":"date"},"height_cm":{"type":"number"},"weight_kg":{"type":"number"},"head_circ_cm":{"type":"number"},"age_months":{"type":"number"},"age_label":{"type":"string"},"note":{"type":"string"}}}',
    'system'
)
ON CONFLICT DO NOTHING;

UPDATE tools SET current_version_id = '00000000-0000-0000-0000-000000000303'
WHERE id = '00000000-0000-0000-0000-000000000203' AND current_version_id IS NULL;

-- Measurement records (newest first; created_at set to the measurement date so the list sorts naturally)
ON CONFLICT DO NOTHING;
